class AuditLog:
    """Append-only audit log with hash chain verification."""

    def __init__(self, store, signing_key: bytes):
        self._store = store          # immutable object storage (e.g. S3 Object Lock)
        self._signing_key = signing_key

    def append(self, event: AuditEvent) -> str:
        last = self._store.get_last_event(event.asset_id)
        event.prev_event_hash = last.hash() if last else ""
        event.sign(self._signing_key)

        # Write to storage BEFORE advancing any state in the application DB
        event_id = self._store.write(event)
        return event_id

    def verify_chain(self, asset_id: str) -> tuple[bool, str | None]:
        """
        Replay the hash chain for an asset's events.
        Returns (True, None) if intact, or (False, first_broken_event_id) if tampered.
        """
        events = self._store.list_events(asset_id, order="asc")
        prev_hash = ""
        for ev in events:
            if ev.prev_event_hash != prev_hash:
                return False, ev.event_id
            if not ev.verify(self._signing_key):
                return False, ev.event_id
            prev_hash = ev.hash()
        return True, None

    def get_timeline(self, asset_id: str) -> list[AuditEvent]:
        """Reconstruct the full governance history for an asset."""
        return self._store.list_events(asset_id, order="asc")

def generate_soc2_deprecation_report(
    audit_log: "AuditLog",
    asset_id: str,
    review_period_start: str,
    review_period_end: str,
) -> dict:
    timeline = audit_log.get_timeline(asset_id)
    in_period = [
        ev for ev in timeline
        if review_period_start <= ev.timestamp <= review_period_end
    ]
    return {
        "asset_id": asset_id,
        "review_period": f"{review_period_start} / {review_period_end}",
        "events_in_period": len(in_period),
        "event_summary": [
            {
                "timestamp": ev.timestamp,
                "event_type": ev.event_type,
                "actor": ev.actor,
                "key_fields": {
                    k: v for k, v in ev.payload.items()
                    if k in ("sunset_date", "successor_id", "approver",
                             "new_sunset_date", "completed_by")
                },
            }
            for ev in in_period
        ],
        "chain_integrity": audit_log.verify_chain(asset_id)[0],
    }

def get_active_deprecations_at_time(
    audit_log: "AuditLog",
    all_asset_ids: list[str],
    query_timestamp: str,
) -> list[dict]:
    """
    Return all assets that were in 'deprecated' state at query_timestamp.
    Used in incident review to check for concurrent migration activity.
    """
    active_deprecations = []
    for asset_id in all_asset_ids:
        timeline = audit_log.get_timeline(asset_id)
        state = "active"
        for ev in timeline:
            if ev.timestamp > query_timestamp:
                break
            if ev.event_type == "DEPRECATION_ANNOUNCED":
                state = "deprecated"
            elif ev.event_type in ("SUNSET_ENFORCED", "ARCHIVED"):
                state = "sunset"
            elif ev.event_type == "MIGRATION_COMPLETED":
                pass  # caller migrated; asset may still be deprecated
        if state == "deprecated":
            active_deprecations.append({
                "asset_id": asset_id,
                "state_at_incident": state,
            })
    return active_deprecations

import datetime

def nightly_audit_integrity_check(
    audit_log: "AuditLog",
    all_asset_ids: list[str],
    deprecation_register,
    alert_channel: str,
) -> None:
    """
    1. Verify hash chain integrity for every asset.
    2. Cross-check: every state transition in the register has a
       corresponding audit event.
    3. Alert on any discrepancy.
    """
    check_date = datetime.date.today().isoformat()
    failures = []

    for asset_id in all_asset_ids:
        ok, broken_at = audit_log.verify_chain(asset_id)
        if not ok:
            failures.append({
                "asset_id": asset_id,
                "issue": "hash_chain_broken",
                "broken_at_event": broken_at,
            })

    # Cross-check: deprecated assets in register must have
    # a DEPRECATION_ANNOUNCED event
    for entry in deprecation_register.get_all_deprecated():
        timeline = audit_log.get_timeline(entry.asset_id)
        has_announced = any(
            ev.event_type == "DEPRECATION_ANNOUNCED" for ev in timeline
        )
        if not has_announced:
            failures.append({
                "asset_id": entry.asset_id,
                "issue": "missing_DEPRECATION_ANNOUNCED_event",
            })

    if failures:
        fire_alert(
            channel=alert_channel,
            severity="critical",
            message=(
                f"Audit trail integrity check FAILED on {check_date}. "
                f"{len(failures)} issue(s): {failures}"
            ),
        )
    else:
        log_metric("audit_integrity_check", status="pass", date=check_date)
